 63→function parseLocation(input: unknown): SubmissionLocation | null {
 64→  if (!input || typeof input !== "object") return null;
 65→  const location = input as { latitude?: unknown; longitude?: unknown };
 66→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
 67→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
 68→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 69→  return { latitude, longitude };
 70→}
