361→async function buildCombinedEvents(): Promise<PointEvent[]> {
362→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
363→  const legacySubmissions = await getLegacySubmissions();
364→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
365→  const seenExternalIds = new Set(
366→    merged
367→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
368→      .filter((value) => value.length > 0),
369→  );
370→  const seenPointIds = new Set(merged.map((event) => event.pointId));
371→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
372→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
373→    if (externalId && seenExternalIds.has(externalId)) continue;
374→    if (seenPointIds.has(seedEvent.pointId)) continue;
375→    merged.push(seedEvent);
376→    if (externalId) seenExternalIds.add(externalId);
377→    seenPointIds.add(seedEvent.pointId);
378→  }
379→  return merged;
380→}
