453→export async function POST(request: Request): Promise<Response> {
454→  const auth = await requireUser(request);
455→  if (!auth) return errorResponse("Unauthorized", 401);
456→  const authContext = toSubmissionAuthContext(auth);
457→  const isAdminUser = authContext?.isAdmin === true;
458→
459→  let body: SubmissionInput;
460→  try {
461→    body = (await request.json()) as SubmissionInput;
462→  } catch {
463→    return errorResponse("Invalid JSON body", 400);
464→  }
465→
466→  const category = normalizeCategory(body?.category as string | undefined);
467→  if (!category || !allowedCategories.includes(category)) {
468→    return errorResponse("Invalid category", 400);
469→  }
470→
471→  const eventType = normalizeEventType(body?.eventType);
472→  const location = parseLocation(body?.location);
473→  const details = normalizeEnrichPayload(
474→    category,
475→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
476→  );
477→  const requestUserAgent = trimString(request.headers.get("user-agent"), 256);
478→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
479→  if (clientDevice) {
480→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
481→    details.clientDevice = clientDevice;
482→  } else if ("clientDevice" in details) {
483→    delete details.clientDevice;
484→  }
485→
486→  const imageBase64 = body?.imageBase64 as string | undefined;
487→  if (!imageBase64) return errorResponse("Photo is required", 400);
488→  const parsedPhoto = parseImagePayload(imageBase64);
489→  if (!parsedPhoto) return errorResponse("Invalid photo format", 400);
490→  if (parsedPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
491→    return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
492→  }
493→
494→  const ipLocation = await getIpLocation(request);
495→  let photoLocation: SubmissionLocation | null = null;
496→  let primaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
497→
498→  try {
499→    primaryPhotoMetadata = await extractPhotoMetadata(parsedPhoto.imageBuffer);
500→    if (primaryPhotoMetadata.gps) {
501→      photoLocation = primaryPhotoMetadata.gps;
502→      if (location) {
503→        const distance = haversineKm(location, photoLocation);
504→        if (distance > SUBMISSION_PHOTO_MATCH_KM) return errorResponse("Photo GPS coordinates do not match submission location", 400);
505→      }
506→      if (ipLocation) {
507→        const distance = haversineKm(ipLocation, photoLocation);
508→        if (distance > IP_PHOTO_MATCH_KM) return errorResponse("Photo location does not match IP location", 400);
509→      }
510→    } else if (!location && !ipLocation) {
511→      return errorResponse("Photo is missing GPS metadata", 400);
512→    }
513→  } catch {
514→    if (!location && !ipLocation) {
515→      return errorResponse("Unable to read photo GPS metadata", 400);
516→    }
517→  }
518→
519→  const finalLocation = photoLocation ?? location ?? ipLocation;
520→  if (!finalLocation) return errorResponse("Missing or invalid location", 400);
521→  if (!isAdminUser && !isWithinBonamoussadi(finalLocation)) {
522→    return errorResponse(
523→      `Location outside Bonamoussadi bounds (${BONAMOUSSADI_BOUNDS.south},${BONAMOUSSADI_BOUNDS.west})-(${BONAMOUSSADI_BOUNDS.north},${BONAMOUSSADI_BOUNDS.east})`,
524→      400,
525→    );
526→  }
527→
528→  try {
529→    const existingEvents = await buildCombinedEvents();
530→    const projectedExisting = projectPointsFromEvents(existingEvents);
531→    let pointId = typeof body.pointId === "string" && body.pointId.trim() ? body.pointId.trim() : crypto.randomUUID();
532→
533→    if (eventType === "CREATE_EVENT") {
534→      const createError = validateCreatePayload(category, details);
535→      if (createError) return errorResponse(createError, 400);
536→    } else {
537→      if (!body.pointId || typeof body.pointId !== "string" || !body.pointId.trim()) {
538→        return errorResponse("pointId is required for ENRICH_EVENT", 400);
539→      }
540→      pointId = body.pointId.trim();
541→      const target = projectedExisting.find((point) => point.pointId === pointId);
542→      if (!target) return errorResponse("Target point not found", 404);
543→      if (target.category !== category) return errorResponse("Category mismatch for target point", 400);
544→
545→      const submittedEntries = Object.entries(details).filter(([, value]) => hasValue(value));
546→      const allowedGaps = new Set(target.gaps);
547→      const filteredEntries = submittedEntries.filter(([field]) => {
548→        const canonical =
549→          field === "hours"
550→            ? "openingHours"
551→            : field === "merchantId"
552→              ? "merchantIdByProvider"
553→              : field === "hasCashAvailable"
554→                ? "hasMin50000XafAvailable"
555→                : field;
556→        return isEnrichFieldAllowed(category, canonical) && allowedGaps.has(canonical);
557→      });
558→      if (!filteredEntries.length) {
559→        return errorResponse("ENRICH_EVENT must include at least one currently missing field", 400);
560→      }
561→      const filteredDetails: SubmissionDetails = {};
562→      for (const [key, value] of filteredEntries) {
563→        filteredDetails[key] = value;
564→      }
565→      Object.assign(details, filteredDetails);
566→      for (const key of Object.keys(details)) {
567→        if (!Object.prototype.hasOwnProperty.call(filteredDetails, key)) {
568→          delete details[key];
569→        }
570→      }
571→      if (clientDevice) {
572→        details.clientDevice = clientDevice;
573→      }
574→    }
575→
576→    const eventId = crypto.randomUUID();
577→    let photoUrl: string | undefined;
578→    try {
579→      photoUrl = await uploadSubmissionPhoto(eventId, parsedPhoto.imageBuffer, parsedPhoto.mime, parsedPhoto.ext);
580→    } catch (error) {
581→      const raw = error instanceof Error ? error.message : String(error);
582→      const lower = raw.toLowerCase();
583→      if (lower.includes("blob") && lower.includes("token")) return errorResponse("Blob storage is not configured", 500);
584→      return errorResponse("Unable to store photo", 500);
585→    }
586→    details.hasPhoto = true;
587→
588→    let secondaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
589→    const secondImageBase64 = body?.secondImageBase64 as string | undefined;
590→    if (secondImageBase64) {
591→      const parsedSecondPhoto = parseImagePayload(secondImageBase64);
592→      if (!parsedSecondPhoto) return errorResponse("Invalid photo format", 400);
593→      if (parsedSecondPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
594→        return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
595→      }
596→
597→      try {
598→        secondaryPhotoMetadata = await extractPhotoMetadata(parsedSecondPhoto.imageBuffer);
599→      } catch {
600→        secondaryPhotoMetadata = null;
601→      }
602→
603→      try {
604→        const secondPhotoUrl = await uploadSubmissionPhoto(
605→          `${eventId}-second`,
606→          parsedSecondPhoto.imageBuffer,
607→          parsedSecondPhoto.mime,
608→          parsedSecondPhoto.ext,
609→        );
610→        details.secondPhotoUrl = secondPhotoUrl;
611→        details.hasSecondaryPhoto = true;
612→      } catch {
613→        return errorResponse("Unable to store photo", 500);
614→      }
615→    }
616→
617→    const primaryPhotoFraud = buildPhotoFraudMetadata({
618→      extracted: primaryPhotoMetadata,
619→      submissionLocation: location,
620→      ipLocation,
621→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
622→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
623→    });
624→    const secondaryPhotoFraud = buildPhotoFraudMetadata({
625→      extracted: secondaryPhotoMetadata,
626→      submissionLocation: location,
627→      ipLocation,
628→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
629→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
630→    });
631→    details.fraudCheck = buildSubmissionFraudCheck({
632→      submissionLocation: location,
633→      effectiveLocation: finalLocation,
634→      ipLocation,
635→      primaryPhoto: primaryPhotoFraud,
636→      secondaryPhoto: secondaryPhotoFraud,
637→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
638→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
639→    });
640→
641→    const now = new Date().toISOString();
642→    const newEvent: PointEvent = {
643→      id: eventId,
644→      pointId,
645→      eventType,
646→      userId: auth.id,
647→      category,
648→      location: finalLocation,
649→      details,
650→      photoUrl,
651→      createdAt: now,
652→      source: typeof details.source === "string" ? details.source : undefined,
653→      externalId: typeof details.externalId === "string" ? details.externalId : undefined,
654→    };
655→
656→    await insertPointEvent(newEvent);
657→
658→    const exifDeviceMake = primaryPhotoMetadata?.deviceMake ?? null;
659→    const exifDeviceModel = primaryPhotoMetadata?.deviceModel ?? null;
660→    const logPayload = {
661→      eventId,
662→      userId: auth.id,
663→      category,
664→      deviceId: clientDevice?.deviceId ?? null,
665→      clientPlatform: clientDevice?.platform ?? null,
666→      clientUserAgent: clientDevice?.userAgent ?? requestUserAgent ?? null,
667→      clientMemoryGb: clientDevice?.deviceMemoryGb ?? null,
668→      clientCpuCores: clientDevice?.hardwareConcurrency ?? null,
669→      clientIsLowEnd: clientDevice?.isLowEnd ?? null,
670→      exifDeviceMake,
671→      exifDeviceModel,
672→    };
673→    if (process.env.NODE_ENV !== "production") {
674→      console.info("[SUBMISSION_DEVICE]", JSON.stringify(logPayload));
675→    }
676→
677→    const profile = await getUserProfile(auth.id);
678→    if (profile) {
679→      profile.XP = (profile.XP ?? 0) + BASE_EVENT_XP;
680→      await upsertUserProfile(auth.id, profile);
681→    }
682→
683→    return jsonResponse(newEvent, { status: 201 });
684→  } catch (error) {
685→    if (isStorageUnavailableError(error)) {
686→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
687→    }
688→    throw error;
689→  }
690→}
