136→function mergeDetails(base: SubmissionDetails, incoming: SubmissionDetails): SubmissionDetails {
137→  const merged: SubmissionDetails = { ...base };
138→  const entries = Object.entries(incoming) as Array<[string, unknown]>;
139→  for (const [key, value] of entries) {
140→    if (!hasValue(value)) continue;
141→    if (Array.isArray(value)) {
142→      merged[key] = value;
143→      continue;
144→    }
145→    if (typeof value === "object" && value !== null && !Array.isArray(value)) {
146→      const prev = merged[key];
147→      if (typeof prev === "object" && prev !== null && !Array.isArray(prev)) {
148→        merged[key] = { ...(prev as Record<string, unknown>), ...(value as Record<string, unknown>) };
149→      } else {
150→        merged[key] = value;
151→      }
152→      continue;
153→    }
154→    merged[key] = value;
155→  }
156→  return merged;
157→}
