203→export function projectPointsFromEvents(events: PointEvent[]): ProjectedPoint[] {
204→  const groups = new Map<string, ProjectedPoint>();
205→  const sorted = [...events].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
206→  for (const event of sorted) {
207→    const normalizedDetails = normalizeDetailsForCategory(event.category, event.details ?? {});
208→    const existing = groups.get(event.pointId);
209→    if (!existing) {
210→      groups.set(
211→        event.pointId,
212→        {
213→          id: event.pointId,
214→          pointId: event.pointId,
215→          category: event.category,
216→          location: event.location,
217→          details: normalizedDetails,
218→          photoUrl: event.photoUrl,
219→          createdAt: event.createdAt,
220→          updatedAt: event.createdAt,
221→          source: event.source,
222→          externalId: event.externalId,
223→          gaps: listMissingFields(event.category, normalizedDetails),
224→          eventsCount: 1,
225→          eventIds: [event.id],
226→        },
227→      );
228→      continue;
229→    }
230→
231→    existing.category = event.category;
232→    existing.location = event.location ?? existing.location;
233→    existing.details = mergeDetails(existing.details, normalizedDetails);
234→    existing.updatedAt = event.createdAt;
235→    existing.eventsCount += 1;
236→    existing.eventIds.push(event.id);
237→    if (event.photoUrl) existing.photoUrl = event.photoUrl;
238→    if (event.source) existing.source = event.source;
239→    if (event.externalId) existing.externalId = event.externalId;
240→    existing.gaps = listMissingFields(existing.category, existing.details);
241→  }
242→
243→  return Array.from(groups.values()).sort(
244→    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
245→  );
246→}
