255→  const source = trimString(details.source) ?? "legacy_submission";
256→  const externalId = trimString(details.externalId) ?? `legacy:${submission.id}`;
257→  return {
258→    id: `legacy-event-${submission.id}`,
259→    pointId: submission.id,
260→    eventType,
261→    userId: submission.userId,
262→    category: submission.category,
