272→export function mergePointEventsWithLegacy(pointEvents: PointEvent[], legacySubmissions: LegacySubmission[]): PointEvent[] {
273→  const merged = [...pointEvents];
274→  const seen = new Set(merged.map((item) => item.id));
275→  for (const legacy of legacySubmissions) {
276→    const converted = legacySubmissionToCreateEvent(legacy);
277→    if (seen.has(converted.id)) continue;
278→    merged.push(converted);
279→    seen.add(converted.id);
280→  }
281→  return merged;
282→}
